import{_ as t,c as o,o as a,a1 as r}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse(`{"title":"Ultrawork Mode: Activate All Features | oh-my-opencode","description":"Learn oh-my-opencode's Ultrawork mode to activate all features with one command. Enables parallel agents, forced completion, and Category + Skills system.","frontmatter":{"title":"Ultrawork Mode: Activate All Features | oh-my-opencode","sidebarTitle":"Ultrawork Mode","subtitle":"Ultrawork Mode: Activate All Features with One Command","description":"Learn oh-my-opencode's Ultrawork mode to activate all features with one command. Enables parallel agents, forced completion, and Category + Skills system.","tags":["ultrawork","background tasks","agent collaboration"],"prerequisite":["start-installation","start-sisyphus-orchestrator"],"order":30},"headers":[],"relativePath":"code-yeongyu/oh-my-opencode/start/ultrawork-mode/index.md","filePath":"code-yeongyu/oh-my-opencode/start/ultrawork-mode/index.md"}`),n={name:"code-yeongyu/oh-my-opencode/start/ultrawork-mode/index.md"};function i(s,e,l,d,c,u){return a(),o("div",null,[...e[0]||(e[0]=[r(`<h1 id="ultrawork-mode-activate-all-features-with-one-command" tabindex="-1">Ultrawork Mode: Activate All Features with One Command <a class="header-anchor" href="#ultrawork-mode-activate-all-features-with-one-command" aria-label="Permalink to &quot;Ultrawork Mode: Activate All Features with One Command&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><ul><li>Activate all advanced features of oh-my-opencode with a single command</li><li>Make multiple AI agents work in parallel like a real team</li><li>Avoid manually configuring multiple agents and background tasks</li><li>Understand the design philosophy and best practices of Ultrawork mode</li></ul><h2 id="your-current-challenges" tabindex="-1">Your Current Challenges <a class="header-anchor" href="#your-current-challenges" aria-label="Permalink to &quot;Your Current Challenges&quot;">​</a></h2><p>You may have encountered these situations during development:</p><ul><li><strong>Too many features, don&#39;t know how to use them</strong>: You have 10 specialized agents, background tasks, LSP tools, but don&#39;t know how to quickly activate them</li><li><strong>Manual configuration required</strong>: Every complex task requires manually specifying agents, background concurrency, and other settings</li><li><strong>Inefficient agent collaboration</strong>: Calling agents in series, wasting time and costs</li><li><strong>Tasks getting stuck midway</strong>: Agents don&#39;t have enough motivation and constraints to complete tasks</li></ul><p>These are all affecting your ability to unleash the true power of oh-my-opencode.</p><h2 id="core-concept" tabindex="-1">Core Concept <a class="header-anchor" href="#core-concept" aria-label="Permalink to &quot;Core Concept&quot;">​</a></h2><p><strong>Ultrawork Mode</strong> is oh-my-opencode&#39;s &quot;one-click activate all&quot; mechanism.</p><div class="info custom-block"><p class="custom-block-title">What is Ultrawork Mode?</p><p>Ultrawork Mode is a special working mode triggered by a keyword. When your prompt contains <code>ultrawork</code> or its abbreviation <code>ulw</code>, the system automatically activates all advanced features: parallel background tasks, deep exploration, forced completion, multi-agent collaboration, and more.</p></div><h3 id="design-philosophy" tabindex="-1">Design Philosophy <a class="header-anchor" href="#design-philosophy" aria-label="Permalink to &quot;Design Philosophy&quot;">​</a></h3><p>Ultrawork mode is based on the following core principles (from the <a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/docs/ultrawork-manifesto.md" target="_blank" rel="noreferrer">Ultrawork Manifesto</a>):</p><table tabindex="0"><thead><tr><th>Principle</th><th>Description</th></tr></thead><tbody><tr><td><strong>Human intervention is a failure signal</strong></td><td>If you need to constantly correct AI output, it means there&#39;s a problem with the system design</td></tr><tr><td><strong>Indistinguishable code</strong></td><td>Code written by AI should be indistinguishable from code written by senior engineers</td></tr><tr><td><strong>Minimize cognitive burden</strong></td><td>You only need to say &quot;what to do&quot;, agents are responsible for &quot;how to do it&quot;</td></tr><tr><td><strong>Predictable, consistent, delegatable</strong></td><td>Agents should be as stable and reliable as a compiler</td></tr></tbody></table><h3 id="activation-mechanism" tabindex="-1">Activation Mechanism <a class="header-anchor" href="#activation-mechanism" aria-label="Permalink to &quot;Activation Mechanism&quot;">​</a></h3><p>When the system detects the <code>ultrawork</code> or <code>ulw</code> keyword:</p><ol><li><strong>Set maximum precision mode</strong>: <code>message.variant = &quot;max&quot;</code></li><li><strong>Display Toast notification</strong>: &quot;Ultrawork Mode Activated - Maximum precision engaged. All agents at your disposal.&quot;</li><li><strong>Inject complete instructions</strong>: Inject 200+ lines of ULTRAWORK instructions to agents, including: <ul><li>Require 100% certainty before starting implementation</li><li>Require parallel use of background tasks</li><li>Force use of Category + Skills system</li><li>Force completion verification (TDD workflow)</li><li>Prohibit any &quot;I can&#39;t do it&quot; excuses</li></ul></li></ol><h2 id="follow-along" tabindex="-1">Follow Along <a class="header-anchor" href="#follow-along" aria-label="Permalink to &quot;Follow Along&quot;">​</a></h2><h3 id="step-1-trigger-ultrawork-mode" tabindex="-1">Step 1: Trigger Ultrawork Mode <a class="header-anchor" href="#step-1-trigger-ultrawork-mode" aria-label="Permalink to &quot;Step 1: Trigger Ultrawork Mode&quot;">​</a></h3><p>Enter a prompt containing the <code>ultrawork</code> or <code>ulw</code> keyword in OpenCode:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ultrawork develop a REST API</span></span></code></pre></div><p>Or more concisely:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ulw add user authentication</span></span></code></pre></div><p><strong>You should see</strong>:</p><ul><li>A Toast notification pops up on the interface: &quot;Ultrawork Mode Activated&quot;</li><li>Agent response starts with &quot;ULTRAWORK MODE ENABLED!&quot;</li></ul><h3 id="step-2-observe-agent-behavior-changes" tabindex="-1">Step 2: Observe Agent Behavior Changes <a class="header-anchor" href="#step-2-observe-agent-behavior-changes" aria-label="Permalink to &quot;Step 2: Observe Agent Behavior Changes&quot;">​</a></h3><p>After activating Ultrawork mode, agents will:</p><ol><li><p><strong>Parallel exploration of codebase</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>delegate_task(agent=&quot;explore&quot;, prompt=&quot;find existing API patterns&quot;, background=true)</span></span>
<span class="line"><span>delegate_task(agent=&quot;explore&quot;, prompt=&quot;find test infrastructure&quot;, background=true)</span></span>
<span class="line"><span>delegate_task(agent=&quot;librarian&quot;, prompt=&quot;find authentication best practices&quot;, background=true)</span></span></code></pre></div></li><li><p><strong>Call Plan agent to create work plan</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>delegate_task(subagent_type=&quot;plan&quot;, prompt=&quot;create detailed plan based on gathered context&quot;)</span></span></code></pre></div></li><li><p><strong>Use Category + Skills to execute tasks</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>delegate_task(category=&quot;visual-engineering&quot;, load_skills=[&quot;frontend-ui-ux&quot;, &quot;playwright&quot;], ...)</span></span></code></pre></div></li></ol><p><strong>You should see</strong>:</p><ul><li>Multiple background tasks running simultaneously</li><li>Agents actively calling specialized agents (Oracle, Librarian, Explore)</li><li>Complete test plans and work breakdown</li><li>Tasks continue executing until 100% complete</li></ul><h3 id="step-3-verify-task-completion" tabindex="-1">Step 3: Verify Task Completion <a class="header-anchor" href="#step-3-verify-task-completion" aria-label="Permalink to &quot;Step 3: Verify Task Completion&quot;">​</a></h3><p>After agents complete, they will:</p><ol><li><strong>Show verification evidence</strong>: Actual test run output, manual verification descriptions</li><li><strong>Confirm all TODOs complete</strong>: Won&#39;t declare completion early</li><li><strong>Summarize work done</strong>: List what was done and why</li></ol><p><strong>You should see</strong>:</p><ul><li>Clear test results (not &quot;should work&quot;)</li><li>All issues resolved</li><li>No unfinished TODO list</li></ul><h2 id="checkpoint-✅" tabindex="-1">Checkpoint ✅ <a class="header-anchor" href="#checkpoint-✅" aria-label="Permalink to &quot;Checkpoint ✅&quot;">​</a></h2><p>After completing the above steps, confirm:</p><ul><li>[ ] You see a Toast notification after entering <code>ulw</code></li><li>[ ] Agent response starts with &quot;ULTRAWORK MODE ENABLED!&quot;</li><li>[ ] You observe parallel background tasks running</li><li>[ ] Agents use the Category + Skills system</li><li>[ ] There&#39;s verification evidence after task completion</li></ul><p>If any item fails, check:</p><ul><li>Is the keyword spelled correctly (<code>ultrawork</code> or <code>ulw</code>)</li><li>Are you in the main session (background tasks won&#39;t trigger the mode)</li><li>Is the configuration file enabled with relevant features</li></ul><h2 id="when-to-use-this-technique" tabindex="-1">When to Use This Technique <a class="header-anchor" href="#when-to-use-this-technique" aria-label="Permalink to &quot;When to Use This Technique&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Scenario</th><th>Use Ultrawork</th><th>Normal Mode</th></tr></thead><tbody><tr><td><strong>Complex new features</strong></td><td>✅ Recommended (requires multi-agent collaboration)</td><td>❌ May not be efficient enough</td></tr><tr><td><strong>Urgent fixes</strong></td><td>✅ Recommended (needs quick diagnosis and exploration)</td><td>❌ May miss context</td></tr><tr><td><strong>Simple modifications</strong></td><td>❌ Overkill (wastes resources)</td><td>✅ More suitable</td></tr><tr><td><strong>Quick idea validation</strong></td><td>❌ Overkill</td><td>✅ More suitable</td></tr></tbody></table><p><strong>Rule of thumb</strong>:</p><ul><li>Task involves multiple modules or systems → Use <code>ulw</code></li><li>Need deep research of codebase → Use <code>ulw</code></li><li>Need to call multiple specialized agents → Use <code>ulw</code></li><li>Single file small change → Don&#39;t need <code>ulw</code></li></ul><h2 id="common-pitfalls" tabindex="-1">Common Pitfalls <a class="header-anchor" href="#common-pitfalls" aria-label="Permalink to &quot;Common Pitfalls&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Important Notes</p><p><strong>1. Don&#39;t use <code>ulw</code> in every prompt</strong></p><p>Ultrawork mode injects a large amount of instructions, which is overkill for simple tasks. Only use it for complex tasks that truly require multi-agent collaboration, parallel exploration, and deep analysis.</p><p><strong>2. Background tasks won&#39;t trigger Ultrawork mode</strong></p><p>The keyword detector skips background sessions to avoid incorrectly injecting the mode into sub-agents. Ultrawork mode only works in the main session.</p><p><strong>3. Ensure Provider configuration is correct</strong></p><p>Ultrawork mode relies on multiple AI models working in parallel. If certain Providers are not configured or unavailable, agents may not be able to call specialized agents.</p></div><h2 id="lesson-summary" tabindex="-1">Lesson Summary <a class="header-anchor" href="#lesson-summary" aria-label="Permalink to &quot;Lesson Summary&quot;">​</a></h2><p>Ultrawork mode achieves the design goal of &quot;activate all features with one command&quot; through keyword triggering:</p><ul><li><strong>Easy to use</strong>: Just enter <code>ulw</code> to activate</li><li><strong>Automatic collaboration</strong>: Agents automatically call other agents and execute background tasks in parallel</li><li><strong>Forced completion</strong>: Complete verification mechanism ensures 100% completion</li><li><strong>Zero configuration</strong>: No need to manually set agent priorities, concurrency limits, etc.</li></ul><p>Remember: Ultrawork mode is designed to make agents work like a real team. You just need to express intent, agents are responsible for execution.</p><h2 id="next-lesson-preview" tabindex="-1">Next Lesson Preview <a class="header-anchor" href="#next-lesson-preview" aria-label="Permalink to &quot;Next Lesson Preview&quot;">​</a></h2><blockquote><p>In the next lesson, we&#39;ll learn <strong><a href="./../../platforms/provider-setup/">Provider Configuration</a></strong>.</p><p>You&#39;ll learn:</p><ul><li>How to configure multiple Providers like Anthropic, OpenAI, Google</li><li>How multi-model strategy automatically degrades and selects optimal models</li><li>How to test Provider connections and quota usage</li></ul></blockquote><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Last updated: 2026-01-26</p></blockquote><table tabindex="0"><thead><tr><th>Feature</th><th>File Path</th><th>Line Numbers</th></tr></thead><tbody><tr><td>Ultrawork design philosophy</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/docs/ultrawork-manifesto.md" target="_blank" rel="noreferrer"><code>docs/ultrawork-manifesto.md</code></a></td><td>1-198</td></tr><tr><td>Keyword detector Hook</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/hooks/keyword-detector/index.ts" target="_blank" rel="noreferrer"><code>src/hooks/keyword-detector/index.ts</code></a></td><td>12-100</td></tr><tr><td>ULTRAWORK instruction template</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/hooks/keyword-detector/constants.ts" target="_blank" rel="noreferrer"><code>src/hooks/keyword-detector/constants.ts</code></a></td><td>54-280</td></tr><tr><td>Keyword detection logic</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/hooks/keyword-detector/detector.ts" target="_blank" rel="noreferrer"><code>src/hooks/keyword-detector/detector.ts</code></a></td><td>26-53</td></tr></tbody></table><p><strong>Key constants</strong>:</p><ul><li><code>KEYWORD_DETECTORS</code>: Keyword detector configuration, including three modes: ultrawork, search, analyze</li><li><code>CODE_BLOCK_PATTERN</code>: Code block regex pattern, used to filter keywords in code blocks</li><li><code>INLINE_CODE_PATTERN</code>: Inline code regex pattern, used to filter keywords in inline code</li></ul><p><strong>Key functions</strong>:</p><ul><li><code>createKeywordDetectorHook()</code>: Creates keyword detector Hook, listens for UserPromptSubmit event</li><li><code>detectKeywordsWithType()</code>: Detects keywords in text and returns type (ultrawork/search/analyze)</li><li><code>getUltraworkMessage()</code>: Generates complete ULTRAWORK mode instructions (selects Planner or normal mode based on agent type)</li><li><code>removeCodeBlocks()</code>: Removes code blocks from text to avoid triggering keywords in code blocks</li></ul><p><strong>Business rules</strong>:</p><table tabindex="0"><thead><tr><th>Rule ID</th><th>Rule Description</th><th>Tag</th></tr></thead><tbody><tr><td>BR-4.8.4-1</td><td>Activate Ultrawork mode when &quot;ultrawork&quot; or &quot;ulw&quot; is detected</td><td>[Fact]</td></tr><tr><td>BR-4.8.4-2</td><td>Ultrawork mode sets <code>message.variant = &quot;max&quot;</code></td><td>[Fact]</td></tr><tr><td>BR-4.8.4-3</td><td>Ultrawork mode displays Toast notification: &quot;Ultrawork Mode Activated&quot;</td><td>[Fact]</td></tr><tr><td>BR-4.8.4-4</td><td>Background task sessions skip keyword detection to avoid mode injection</td><td>[Fact]</td></tr><tr><td>BR-4.8.4-5</td><td>Non-main sessions only allow ultrawork keyword, blocking other mode injection</td><td>[Fact]</td></tr></tbody></table></details>`,54)])])}const g=t(n,[["render",i]]);export{h as __pageData,g as default};
